#include <stdio.h>
#include <limits.h>

int main() {

    int r, w, n;
    scanf("%d %d %d", &r, &w, &n);

    long long req = 1LL * r * w;

    int a[n];

    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    int i = 0, j = 0;
    long long sum = 0;

    int mini = INT_MAX;

    while (j < n) {

        sum += a[j];

        while (sum >= req) {

            if (j - i + 1 < mini) {
                mini = j - i + 1;
            }

            sum -= a[i];
            i++;
        }

        j++;
    }

    if (mini == INT_MAX)
        printf("0\n");
    else
        printf("%d\n", mini);

    return 0;
}

