import java.util.*;

public class Main {

    public static void main(String[] args) {

        Scanner sc = new Scanner(System.in);

        int r = sc.nextInt();
        int w = sc.nextInt();
        int n = sc.nextInt();

        long req = 1L * r * w;

        int[] a = new int[n];

        for (int i = 0; i < n; i++) {
            a[i] = sc.nextInt();
        }

        int i = 0, j = 0;

        long sum = 0;

        int mini = Integer.MAX_VALUE;

        while (j < n) {

            sum += a[j];

            while (sum >= req) {

                mini = Math.min(mini, j - i + 1);

                sum -= a[i];
                i++;
            }

            j++;
        }

        if (mini == Integer.MAX_VALUE)
            System.out.println(0);
        else
            System.out.println(mini);

        sc.close();
    }
}
